.darma-loader-darma-custom-772 {
  color: var(--loader-color, #f97316);
  --loader-secondary-color: #fdba74;
  --loader-bg: #ffffff;
height: 15px;
aspect-ratio: 5;
-webkit-mask: linear-gradient(90deg,#0000 ,currentColor 20% 80%,#0000);
background: radial-gradient(closest-side at 37.5% 50%,currentColor 94%,#0000) 0/calc(80%/3) 100%;
animation: darma-loader-darma-custom-772-l48 .75s infinite linear;
}
@keyframes darma-loader-darma-custom-772-l48 {
100% {background-position: 36.36%}
}

